def countOfSmallerNumbersAfterSelf(data: str) -> List[int]:
    nums = list(map(int, data.split()))
    result = []
    n = len(nums)
    for i in range(n):
        count = 0
        for j in range(i + 1, n):
            if nums[j] < nums[i]:
                count += 1
        result.append(count)
    return result

