class Solution {
    public:
    vector<int> countOfSmallerNumbersAfterSelf(const vector<int>& data) {
        int n = data.size();
        vector<int> result(n, 0);
        vector<pair<int, int>> indexedData(n);
        for (int i = 0; i < n; i++) {
            indexedData[i] = {
                data[i], i
            }
            ;
        }
        mergeSort(indexedData, result, 0, n - 1);
        return result;
    }
    private:
    void mergeSort(vector<pair<int, int>>& indexedData, vector<int>& result, int left, int right) {
        if (left >= right) return;
        int mid = left + (right - left) / 2;
        mergeSort(indexedData, result, left, mid);
        mergeSort(indexedData, result, mid + 1, right);
        merge(indexedData, result, left, mid, right);
    }
    void merge(vector<pair<int, int>>& indexedData, vector<int>& result, int left, int mid, int right) {
        int j = mid + 1;
        for (int i = left; i <= mid; i++) {
            while (j <= right && indexedData[i].first > indexedData[j].first) {
                j++;
            }
            result[indexedData[i].second] += (j - (mid + 1));
        }
        vector<pair<int, int>> temp;
        int leftIndex = left, rightIndex = mid + 1;
        while (leftIndex <= mid && rightIndex <= right) {
            if (indexedData[leftIndex] <= indexedData[rightIndex]) {
                temp.push_back(indexedData[leftIndex++]);
            }
            else {
                temp.push_back(indexedData[rightIndex++]);
            }
        }
        while (leftIndex <= mid) {
            temp.push_back(indexedData[leftIndex++]);
        }
        while (rightIndex <= right) {
            temp.push_back(indexedData[rightIndex++]);
        }
        for (int i = 0; i < temp.size(); i++) {
            indexedData[left + i] = temp[i];
        }
    }
