package main

func countOfSmallerNumbersAfterSelf(data []int) []int {
    n := len(data)
    if n == 0 {
        return nil
    }
    count := make([]int, n)
    indexedData := make([][2]int, n)
    for i := 0; i < n; i++ {
        indexedData[i] = [2]int{data[i], i}
    }
    mergeSort(indexedData, count)
    return count
}

func mergeSort(arr [][2]int, count []int) [][2]int {
    if len(arr) <= 1 {
        return arr
    }
    mid := len(arr) / 2
    left := mergeSort(arr[:mid], count)
    right := mergeSort(arr[mid:], count)

    return merge(left, right, count)
}

func merge(left, right [][2]int, count []int) [][2]int {
    i, j := 0, 0
    n := len(left) + len(right)
    sorted := make([][2]int, n)
    for k := 0; k < n; k++ {
        if i < len(left) && (j >= len(right) || left[i][0] <= right[j][0]) {
            sorted[k] = left[i]
            count[left[i][1]] += j
            i++
        } else {
            sorted[k] = right[j]
            j++
        }
    }
    return sorted
}

