public class Solution {
    public int[] countOfSmallerNumbersAfterSelf(int[] data) {
        int n = data.Length;
        int[] result = new int[n];
        int[] indices = new int[n];
        for (int i = 0; i < n; i++) {
            indices[i] = i;
        }
        MergeSort(data, indices, result, 0, n - 1);
        return result;
    }

    private void MergeSort(int[] data, int[] indices, int[] result, int left, int right) {
        if (left >= right) return;
        int mid = left + (right - left) / 2;
        MergeSort(data, indices, result, left, mid);
        MergeSort(data, indices, result, mid + 1, right);
        Merge(data, indices, result, left, mid, right);
    }

    private void Merge(int[] data, int[] indices, int[] result, int left, int mid, int right) {
        int[] tempIndices = new int[right - left + 1];
        int i = left, j = mid + 1, k = 0, count = 0;

        while (i <= mid && j <= right) {
            if (data[indices[i]] > data[indices[j]]) {
                count++;
                tempIndices[k++] = indices[j++];
            } else {
                result[indices[i]] += count;
                tempIndices[k++] = indices[i++];
            }
        }

        while (i <= mid) {
            result[indices[i]] += count;
            tempIndices[k++] = indices[i++];
        }

        while (j <= right) {
            tempIndices[k++] = indices[j++];
        }

        for (int m = 0; m < tempIndices.Length; m++) {
            indices[left + m] = tempIndices[m];
        }
    }
}
